/* wms-report-owicxibobhistorysearch-sql-oracle.xml - selectOwIcInfo */
#{GRIDPAGING_ROWNUMTYPE_TOP}

 ORDER BY X.CTKEY, X.OWKEY, X.ICKEY
#{GRIDPAGING_ROWNUMTYPE_BOTTOM}

mapper.sql:
SELECT X.* FROM ( SELECT A.IOTYPE, A.IBHDTYPE, A.CTKEY, B.CTNAME, A.OWKEY, C.OWNAME, A.ICKEY, D.ICNAME, E.ICGRNAME , A.LOGGRPCD, A.IN_QTY, A.OUT_QTY, SUBSTR(A.IBCONFIRMDATE,1,8) AS IBCONFIRMDATE_IBOB, A.IBCONFIRMDATE , A.IVATKEY, A.ATTRIBUTE3, A.PRODUCTLOT, A.SPEC, A.UOM, A.PRODUCTDATE, A.EXPIREDATE, A.IBEXPECTDATE FROM ( SELECT 'IB' AS IOTYPE, TO1.CTKEY, TO1.OWKEY, TO1.ICKEY, TO1.IVATKEY, TO1.LOGGRPCD, TO1.ICGRKEY , TO1.IBHDTYPE, TO1.IBCONFIRMDATE, TO1.CFQTY AS IN_QTY, 0 OUT_QTY, TO1.ATTRIBUTE3, TO1.PRODUCTLOT , TO1.SPEC, TO1.UOM, TO1.PRODUCTDATE, TO1.EXPIREDATE, TO1.IBEXPECTDATE FROM ( SELECT T1.CTKEY, T1.OWKEY, T1.ICKEY, T1.IVATKEY, T1.LOGGRPCD, T1.ICGRKEY , T1.IBHDTYPE, T1.IBCONFIRMDATE, SUM(T1.CFQTY) AS CFQTY, T1.ATTRIBUTE3 , T1.PRODUCTLOT, T1.SPEC, T1.UOM, T1.PRODUCTDATE, T1.EXPIREDATE, T1.IBEXPECTDATE FROM ( SELECT B.CTKEY, B.OWKEY, C.ICKEY, F.IVATKEY, E.LOGGRPCD, E.ICGRKEY , B.IBHDTYPE, COALESCE(CAST(D.CFQTY AS NUMERIC), 0) AS CFQTY, F.IBCONFIRMDATE, F.ATTRIBUTE3 , F.PRODUCTLOT, E.SPEC, C.UOM, F.PRODUCTDATE, F.EXPIREDATE, B.IBEXPECTDATE FROM TWORK_INFO_IB_HD B INNER JOIN TWORK_INFO_IB_DT C ON C.CTKEY = B.CTKEY AND C.IBHDKEY = B.IBHDKEY INNER JOIN TWORK_INFO_IBCF_DT D ON D.CTKEY = C.CTKEY AND D.EXTERNORDERKEY = C.EXTERNORDERKEY AND D.EXTERNORDERLINENUM = C.EXTERNORDERLINENUM INNER JOIN TWORK_MST_IC E ON E.CTKEY = C.CTKEY AND E.OWKEY = C.OWKEY AND E.ICKEY = C.ICKEY INNER JOIN TWORK_INFO_IVAT F ON F.CTKEY = C.CTKEY AND F.ICKEY = C.ICKEY AND F.IVATKEY = D.TO_IVATKEY WHERE B.CTKEY = #{ctkey} AND B.IBHDTYPE IN ('10','40') AND C.WKSTATUS IN ('90', '91')
UNION ALL
SELECT B.CTKEY, B.OWKEY, C.ICKEY, F.IVATKEY AS IVATKEY, D.LOGGRPCD, D.ICGRKEY , B.IBHDTYPE, COALESCE(C.CFQTY, 0) AS CFQTY, F.IBCONFIRMDATE, F.ATTRIBUTE3 , F.PRODUCTLOT, D.SPEC, D.UOM, F.PRODUCTDATE, F.EXPIREDATE, B.IBEXPECTDATE FROM TWORK_INFO_IB_HD B INNER JOIN TWORK_INFO_IB_DT C ON C.CTKEY = B.CTKEY AND C.IBHDKEY = B.IBHDKEY INNER JOIN TWORK_MST_IC D ON D.CTKEY = C.CTKEY AND D.OWKEY = C.OWKEY AND D.ICKEY = C.ICKEY INNER JOIN TWORK_INFO_IVAT F ON F.CTKEY = B.CTKEY AND F.ICKEY = C.ICKEY AND F.IVATKEY = C.TO_IVATKEY WHERE B.CTKEY = #{ctkey} AND B.IBHDTYPE NOT IN ('10', '40') AND C.WKSTATUS IN ('90', '91') ) T1 GROUP BY T1.CTKEY, T1.OWKEY, T1.ICKEY, T1.IVATKEY, T1.LOGGRPCD, T1.ICGRKEY , T1.IBHDTYPE, T1.IBCONFIRMDATE, T1.ATTRIBUTE3 , T1.PRODUCTLOT, T1.SPEC, T1.UOM, T1.PRODUCTDATE, T1.EXPIREDATE, T1.IBEXPECTDATE ) TO1
UNION ALL
SELECT 'OB' AS IOTYPE, T1.CTKEY, T1.OWKEY, T1.ICKEY, T1.IVATKEY, T1.LOGGRPCD, T1.ICGRKEY , T1.OBHDTYPE, T1.OBCONFIRMDATE, 0 IN_QTY ,SUM(T1.CFQTY) AS OUT_QTY, T1.ATTRIBUTE3 , T1.PRODUCTLOT, T1.SPEC, T1.UOM, T1.PRODUCTDATE, T1.EXPIREDATE, T1.OBREQUESTDATE FROM ( SELECT A.CTKEY, A.OWKEY, B.ICKEY, F.IVATKEY, C.LOGGRPCD, C.ICGRKEY , A.OBHDTYPE, COALESCE(D.CFQTY, 0) AS CFQTY, B.OBCONFIRMDATE, F.ATTRIBUTE3 , F.PRODUCTLOT, C.SPEC, B.UOM, F.PRODUCTDATE, F.EXPIREDATE, A.OBREQUESTDATE FROM TWORK_INFO_OB_HD A INNER JOIN TWORK_INFO_OB_DT B ON B.CTKEY = A.CTKEY AND B.OWKEY = A.OWKEY AND B.OBHDKEY = A.OBHDKEY INNER JOIN TWORK_MST_IC C ON C.CTKEY = B.CTKEY AND C.OWKEY = B.OWKEY AND C.ICKEY = B.ICKEY INNER JOIN TWORK_INFO_PI_DT D ON D.CTKEY = B.CTKEY AND D.OWKEY = B.OWKEY AND D.ICKEY = B.ICKEY AND D.OBHDKEY = B.OBHDKEY AND D.OBDTKEY = B.OBDTKEY INNER JOIN TWORK_INFO_IVAT F ON F.CTKEY = A.CTKEY AND F.ICKEY = B.ICKEY AND F.IVATKEY = D.IVATKEY WHERE A.CTKEY = #{ctkey} AND B.WKSTATUS IN ('90', '91') AND D.WKSTATUS IN ('90', '91') AND A.OBHDTYPE = '10'
UNION ALL
SELECT A.CTKEY, A.OWKEY, B.ICKEY, F.IVATKEY, C.LOGGRPCD, C.ICGRKEY , A.OBHDTYPE, COALESCE(D.CFQTY, 0) AS CFQTY, B.OBCONFIRMDATE, F.ATTRIBUTE3 , F.PRODUCTLOT, C.SPEC, B.UOM, F.PRODUCTDATE, F.EXPIREDATE, A.OBREQUESTDATE FROM TWORK_INFO_OB_HD A INNER JOIN TWORK_INFO_OB_DT B ON B.CTKEY = A.CTKEY AND B.OWKEY = A.OWKEY AND B.OBHDKEY = A.OBHDKEY
INNER JOIN TWORK_MST_IC C ON C.CTKEY = B.CTKEY AND C.OWKEY = B.OWKEY AND C.ICKEY = B.ICKEY
INNER JOIN TWORK_INFO_PI_DT D ON D.CTKEY = B.CTKEY AND D.OWKEY = B.OWKEY AND D.ICKEY = B.ICKEY AND D.OBHDKEY = B.OBHDKEY AND D.OBDTKEY = B.OBDTKEY INNER JOIN TWORK_INFO_IVAT F ON F.CTKEY = A.CTKEY AND F.ICKEY = B.ICKEY AND F.IVATKEY = D.IVATKEY WHERE A.CTKEY = #{ctkey} AND B.WKSTATUS IN ('90', '91') AND D.WKSTATUS IN ('90', '91') AND A.OBHDTYPE != '10' ) T1 GROUP BY T1.CTKEY, T1.OWKEY ,T1.ICKEY ,T1.IVATKEY ,T1.LOGGRPCD ,T1.ICGRKEY , T1.OBHDTYPE, T1.OBCONFIRMDATE, T1.ATTRIBUTE3, T1.PRODUCTLOT , T1.SPEC, T1.UOM, T1.PRODUCTDATE, T1.EXPIREDATE, T1.OBREQUESTDATE ) A INNER JOIN TWORK_MST_CT B ON B.CTKEY = A.CTKEY INNER JOIN TWORK_MST_OW C ON C.OWKEY = A.OWKEY INNER JOIN TWORK_MST_IC D ON D.CTKEY = A.CTKEY AND D.OWKEY = A.OWKEY AND D.ICKEY = A.ICKEY INNER JOIN TWORK_MST_ICGR E ON E.CTKEY = A.CTKEY AND E.OWKEY= A.OWKEY AND E.ICGRKEY = A.ICGRKEY ) X WHERE X.CTKEY = #{ctkey} AND X.OWKEY = #{owkey} AND X.ICKEY = #{ickey}
AND X.IOTYPE = #{cboIogbtype}
AND X.IBHDTYPE = #{cboIbhdtype}
AND X.IBCONFIRMDATE_IBOB >= #{calFromdate}
AND X.IBCONFIRMDATE_IBOB <= #{calTodate}

